import React, { useState, useEffect } from 'react';
import { database } from './firebase';
import { ref, onValue, set, update } from "firebase/database";
import { User, Lock, LogOut, CheckCircle, XCircle, Database, FileSpreadsheet } from 'lucide-react';
import * as XLSX from 'xlsx'; // Librería para el Excel
import './App.css';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [user, setUser] = useState('');
  const [pass, setPass] = useState('');
  const [personal, setPersonal] = useState([]);

  // CARGA MASIVA (Datos de tu Sheets original)
  const ejecutarCargaMasiva = () => {
    const lista = [
      { id: "30968251", nombre: "ABRAHAM DAVID MARCANO", puesto: "ASESOR DE VENTAS" },
      { id: "32277640", nombre: "WILSON JOSE QUINTERO", puesto: "ASESOR DE VENTAS" },
      { id: "29950295", nombre: "YHONDEIVER JOSÉ ACIVE", puesto: "ASESOR DE VENTAS" },
      { id: "25385511", nombre: "WILLY SILVA", puesto: "OPERADOR INTEGRAL" },
      { id: "25990413", nombre: "RICHARD MORENO", puesto: "OPERADOR INTEGRAL" },
      { id: "22045441", nombre: "MARLÍN PEREIRA", puesto: "OPERADOR INTEGRAL" },
      { id: "17919647", nombre: "HERNAN SANCHEZ", puesto: "OPERADOR INTEGRAL" },
      { id: "27623556", nombre: "EDUINZON VARGUILLA", puesto: "ALMACENISTA" }
    ];

    if (window.confirm("¿Cargar personal a Firebase?")) {
      lista.forEach(emp => {
        set(ref(database, `asistencia/${emp.id}`), { ...emp, estado: "AUSENTE" });
      });
      alert("¡Data cargada!");
    }
  };

  // FUNCIÓN PARA DESCARGAR EL EXCEL
  const descargarReporte = () => {
    if (personal.length === 0) return alert("No hay datos para exportar");
    
    // Formateamos la data para el Excel
    const dataExcel = personal.map(p => ({
      Cedula: p.id,
      Nombre: p.nombre,
      Cargo: p.puesto,
      Asistencia: p.estado,
      Fecha: new Date().toLocaleDateString()
    }));

    const ws = XLSX.utils.json_to_sheet(dataExcel);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Asistencia");
    XLSX.writeFile(wb, `Reporte_Asistencia_${new Date().toLocaleDateString()}.xlsx`);
  };

  useEffect(() => {
    if (isLoggedIn) {
      onValue(ref(database, 'asistencia'), (snap) => {
        const data = snap.val();
        if (data) setPersonal(Object.keys(data).map(k => ({ id: k, ...data[k] })));
      });
    }
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (user === 'ADMCanguro' && pass === 'SRT2026') setIsLoggedIn(true);
    else alert('Acceso denegado');
  };

  if (!isLoggedIn) return (
    <div className="login-container">
      <form onSubmit={handleLogin} className="login-box">
        <h2 style={{color:'#ffd900'}}>MATRIZ SRT 2026</h2>
        <input type="text" placeholder="Usuario" onChange={e => setUser(e.target.value)} required />
        <input type="password" placeholder="Clave" onChange={e => setPass(e.target.value)} required />
        <button type="submit">INGRESAR</button>
      </form>
    </div>
  );

  return (
    <div className="dashboard">
      <header className="header">
        <h1>ASISTENCIA CANGURO</h1>
        <div className="header-buttons">
          <button onClick={descargarReporte} className="btn-report">
            <FileSpreadsheet size={16}/> Reporte Excel
          </button>
          <button onClick={ejecutarCargaMasiva} className="btn-admin">
            <Database size={16}/> Cargar Datos
          </button>
          <button onClick={() => setIsLoggedIn(false)} className="btn-logout">Salir</button>
        </div>
      </header>
      <div className="grid-container">
        {personal.map(p => (
          <div key={p.id} className={`card ${p.estado === 'PRESENTE' ? 'presente' : 'ausente'}`} 
               onClick={() => update(ref(database, `asistencia/${p.id}`), { estado: p.estado === 'PRESENTE' ? 'AUSENTE' : 'PRESENTE' })}>
            <div className="card-info">
              <span className="nombre">{p.nombre}</span>
              <span className="puesto">{p.puesto}</span>
            </div>
            {p.estado === 'PRESENTE' ? <CheckCircle color="#00ff00" /> : <XCircle color="#ff0000" />}
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;